dark.customCSS:
/* --- KINETIC THERMAL: FUSION CORE UI --- */

/* Industrial Plating */
.prose, .bg-gray-850, #sidebar {
	background: rgba(7, 15, 26, 0.8) !important;
	backdrop-filter: blur(20px) !important;
	-webkit-backdrop-filter: blur(20px) !important;
	border: 1px solid rgba(0, 140, 255, 0.2) !important;
	border-radius: 0px !important;
	clip-path: polygon(0 0, 97% 0, 100% 3%, 100% 100%, 3% 100%, 0 97%);
	box-shadow: 0 0 20px rgba(0, 0, 0, 0.5), inset 0 0 15px rgba(255, 95, 0, 0.05) !important;
}

/* Thermal Light-Bleed Headers */
.prose h1, .prose h2, .prose h3 {
	color: #ff9d00 !important;
	font-family: 'JetBrains Mono', monospace !important;
	text-transform: uppercase;
	letter-spacing: 3px;
	filter: drop-shadow(0 0 8px rgba(255, 157, 0, 0.4));
}

/* Plasma Input Fields */
input, textarea {
	background: rgba(2, 4, 8, 0.9) !important;
	border: 1px solid #008cff !important;
	border-left: 4px solid #ff9d00 !important;
	color: #e0f2ff !important;
	border-radius: 0px !important;
	transition: border 0.3s ease;
}
input:focus, textarea:focus {
	border-color: #ff9d00 !important;
	box-shadow: 0 0 15px rgba(255, 157, 0, 0.2) !important;
}

/* Fusion Primary Buttons */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: #ff9d00 !important;
	color: #020408 !important;
	border-radius: 2px !important;
	font-weight: 900 !important;
	text-transform: uppercase;
	letter-spacing: 1px;
	border: none !important;
	box-shadow: 0 0 15px rgba(255, 157, 0, 0.4) !important;
	transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

button.bg-blue-500:hover {
	background: #fff !important;
	box-shadow: 0 0 30px rgba(255, 255, 255, 0.6) !important;
	transform: translateY(-1px);
}

/* Core Conduit Scrollbar */
::-webkit-scrollbar {
	width: 6px;
}
::-webkit-scrollbar-thumb {
	background: linear-gradient(to bottom, #ff9d00, #008cff) !important;
	border-radius: 0px;
}
::-webkit-scrollbar-track {
	background: #020408 !important;
}

dark.canvasScript:
/**
 * Title: Plasma Arc Discharge
 * Description: Magnetic nodes that generate flickering orange energy arcs between themselves and the mouse conductor.
 */

const CONFIG = {
    nodeCount: 40,
    arcDistance: 160,
    nodeColor: 'rgba(0, 140, 255, 0.3)',
    arcColor: 'rgba(255, 157, 0, 0.6)',
    conductorColor: 'rgba(255, 255, 255, 0.9)',
    flickerSpeed: 0.1
};

let canvas, ctx, w, h;
let nodes = [];
let mouse = { x: -5000, y: -5000, active: false };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y; mouse.active = true;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    nodes = [];
    for (let i = 0; i < CONFIG.nodeCount; i++) {
        nodes.push({
            x: Math.random() * w, y: Math.random() * h,
            vx: (Math.random() - 0.5) * 1.2, vy: (Math.random() - 0.5) * 1.2,
            size: Math.random() * 2 + 1
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    // 1. Update and Draw Nodes
    for (let i = 0; i < nodes.length; i++) {
        let n = nodes[i];
        n.x += n.vx; n.y += n.vy;

        if (n.x < 0 || n.x > w) n.vx *= -1;
        if (n.y < 0 || n.y > h) n.vy *= -1;

        ctx.fillStyle = CONFIG.nodeColor;
        ctx.beginPath();
        ctx.arc(n.x, n.y, n.size, 0, Math.PI * 2);
        ctx.fill();

        // 2. Conductor interaction (Mouse)
        let dxM = mouse.x - n.x; let dyM = mouse.y - n.y; let distM = Math.hypot(dxM, dyM);
        if (distM < CONFIG.arcDistance) {
            drawArc(n.x, n.y, mouse.x, mouse.y, true);
        }

        // 3. Inter-node Arcs
        for (let j = i + 1; j < nodes.length; j++) {
            let n2 = nodes[j];
            let dist = Math.hypot(n2.x - n.x, n2.y - n.y);
            if (dist < CONFIG.arcDistance) {
                drawArc(n.x, n.y, n2.x, n2.y, false);
            }
        }
    }
    requestAnimationFrame(render);
}

function drawArc(x1, y1, x2, y2, isMouse) {
    // Create a jagged "plasma flickering" path
    ctx.beginPath();
    ctx.moveTo(x1, y1);

    let midX = (x1 + x2) / 2 + (Math.random() - 0.5) * 15;
    let midY = (y1 + y2) / 2 + (Math.random() - 0.5) * 15;

    ctx.quadraticCurveTo(midX, midY, x2, y2);

    ctx.strokeStyle = isMouse ? CONFIG.conductorColor : CONFIG.arcColor;
    ctx.lineWidth = Math.random() < 0.5 ? 0.5 : 1.5; // Flicker width
    ctx.globalAlpha = Math.random() * 0.8 + 0.2;     // Flicker opacity
    ctx.stroke();
    ctx.globalAlpha = 1.0;
}

